args.sparql:
SELECT (COUNT(DISTINCT ?game) AS ?count) WHERE {
  ?series wdt:P31 wd:Q285108 ;
          wdt:P585 ?year ;
          wdt:P1262 wd:Q1347 ;
          wdt:P1262 wd:Q1340 .
  FILTER (SUBSTR(STR(?year), 1, 4) IN ('1977', '1978', '2008', '2009')).
  ?series wdt:P527 ?game .
  ?game wdt:P929 ?attendance .
  FILTER (?attendance > 50000) .
}

